CREATE OR REPLACE FUNCTION public.assign_to_group(p_user_id uuid, p_group_id integer)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
begin
  if not exists (
    select 1
    from public.user_group ug
    where ug.group_id = p_group_id
      and ug.owner = auth.uid()
  ) then
    raise exception 'not group owner';
  end if;

  insert into public.user_group_assignment(group_id, user_id)
  values (p_group_id, p_user_id)
  on conflict (group_id, user_id) do nothing;
end;
$function$

CREATE OR REPLACE FUNCTION public.create_group(p_group_name text)
 RETURNS bigint
 LANGUAGE plpgsql
AS $function$
declare
  v_group_id bigint;
begin
  if p_group_name is null or btrim(p_group_name) = '' then
    raise exception 'group_name cannot be null/empty';
  end if;

  insert into public.user_group (owner, group_name)
  values (auth.uid(), p_group_name)
  returning group_id into v_group_id;

  return v_group_id;
end;
$function$

CREATE OR REPLACE FUNCTION public.delete_group(p_group_id integer)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
begin
  if not exists (
    select 1
    from public.user_group ug
    where ug.group_id = p_group_id
      and ug.owner = auth.uid()
  ) then
    raise exception 'not group owner';
  end if;

  delete from public.user_group where group_id = p_group_id;
  -- assignments are deleted automatically via FK ON DELETE CASCADE
end;
$function$

CREATE OR REPLACE FUNCTION public.log_tokens(p_used_tokens integer)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
  m record;
  used integer;
  next_used integer;
BEGIN
  IF p_used_tokens IS NULL OR p_used_tokens <= 0 THEN
    RAISE EXCEPTION 'used_tokens must be a positive integer';
  END IF;

  SELECT * INTO m FROM public._get_user_payment_model_level();
  IF NOT FOUND THEN
    RAISE EXCEPTION 'No payment model found for user %', auth.uid();
  END IF;

  SELECT COALESCE(SUM(tokens), 0)
  INTO used
  FROM public.amezit_runtime_usage uur
  WHERE uur.uuid = auth.uid()
    AND uur.day = CURRENT_DATE;

  next_used := used + p_used_tokens;

  IF NOT COALESCE(m.infinity_tokens, false) THEN
    IF next_used > COALESCE(m.max_tokens_per_d, 0) THEN
      RAISE EXCEPTION 'Daily token limit exceeded';
    END IF;
  END IF;

  INSERT INTO public.amezit_runtime_usage (uuid, day, runtime, tokens)
  VALUES (auth.uid(), CURRENT_DATE, 0, p_used_tokens)
  ON CONFLICT (uuid, day)
  DO UPDATE SET
    tokens = public.amezit_runtime_usage.tokens + EXCLUDED.tokens,
    runtime = public.amezit_runtime_usage.runtime;
END;
$function$

CREATE OR REPLACE FUNCTION public.start_chat_session(p_owner_id uuid, p_project_id bigint, p_chat_action_type chat_action_types)
 RETURNS chat_sessions
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
    v_company_id bigint;
    v_new_chat public.chat_sessions;
begin
    select p.company_id::bigint
      into v_company_id
      from public.profiles p
     where p.user_id_auth = p_owner_id
     limit 1;

    if not found then
        raise exception 'No profile found for owner_id %', p_owner_id;
    end if;

    if v_company_id is null then
        raise exception 'Profile found, but company_id is null for owner_id %', p_owner_id;
    end if;

    insert into public.chat_sessions (
        owner_id,
        project_id,
        chat_action_type,
        company_id
    )
    values (
        p_owner_id,
        p_project_id,
        p_chat_action_type,
        v_company_id
    )
    returning * into v_new_chat;

    return v_new_chat;
end;
$function$

CREATE OR REPLACE FUNCTION public.update_parameters(p_project_id bigint, p_group_key text, p_param_name text, p_param_value text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_group text := lower(btrim(coalesce(p_group_key, '')));
  v_name  text := lower(btrim(coalesce(p_param_name, '')));
  v_allowed boolean;
  v_rows int8;
begin
  if p_project_id is null then
    raise exception 'p_project_id must not be null';
  end if;

  if v_group = '' then
    raise exception 'p_group_key must not be empty';
  end if;

  if v_name = '' then
    raise exception 'p_param_name must not be empty';
  end if;

  select exists (
    select 1
    from public.cust_project_params c
    where lower(c.param_group) = v_group
      and lower(c.param_key)   = v_name
  )
  into v_allowed;

  if not v_allowed then
    return jsonb_build_object(
      'status', 'skipped',
      'reason', 'param_key not allowed by cust_project_params',
      'project_id', p_project_id,
      'parameter_group', v_group,
      'parameter_name', v_name
    );
  end if;

  insert into public.project_params (
    project_id,
    parameter_group,
    parameter_name,
    parameter_value
  )
  values (
    p_project_id,
    v_group,
    v_name,
    p_param_value
  )
  on conflict (project_id, parameter_group, parameter_name)
  do update set
    parameter_value = excluded.parameter_value;

  get diagnostics v_rows = row_count;

  return jsonb_build_object(
    'status', 'ok',
    'affected_rows', v_rows,
    'project_id', p_project_id,
    'parameter_group', v_group,
    'parameter_name', v_name
  );
end;
$function$
